// Collect health summary from all Netdata hosts
const hostString = process.env.NETDATA_HOSTS || '';
const hosts = {};
hostString.split(',').forEach(h => {
  const colonIdx = h.indexOf(':http');
  if (colonIdx > 0) {
    hosts[h.slice(0, colonIdx).trim()] = 'http' + h.slice(colonIdx + 1).trim();
  }
});

const lines = ['📊 **NOLA Weekly Health Digest**', ''];

await Promise.all(Object.entries(hosts).map(async ([name, baseUrl]) => {
  try {
    const resp = await $helpers.httpRequest({ method: 'GET', url: `${baseUrl}/api/v1/allmetrics?format=json`, timeout: 10000 });
    const d = typeof resp === 'string' ? JSON.parse(resp) : resp;

    const cpuIdle = d?.['system.cpu']?.dimensions?.idle?.value;
    const cpuUsed = cpuIdle !== undefined ? (100 - cpuIdle).toFixed(1) + '%' : 'N/A';

    const ramUsed = d?.['system.ram']?.dimensions?.used?.value;
    const ramFree = d?.['system.ram']?.dimensions?.free?.value;
    const ramBuff = (d?.['system.ram']?.dimensions?.buffers?.value || 0) + (d?.['system.ram']?.dimensions?.cached?.value || 0);
    let ramStr = 'N/A';
    if (ramUsed !== undefined && ramFree !== undefined) {
      const total = ramUsed + ramFree + ramBuff;
      const pct   = total > 0 ? ((ramUsed / total) * 100).toFixed(1) : '0';
      ramStr = `${pct}%`;
    }

    const uptime  = d?.['system.uptime']?.dimensions?.uptime?.value;
    const uptimeStr = uptime !== undefined
      ? uptime > 86400 ? `${Math.floor(uptime / 86400)}d ${Math.floor((uptime % 86400) / 3600)}h`
        : `${Math.floor(uptime / 3600)}h ${Math.floor((uptime % 3600) / 60)}m`
      : 'N/A';

    lines.push(`**${name}**: CPU ${cpuUsed} | RAM ${ramStr} | Uptime ${uptimeStr}`);
  } catch (err) {
    lines.push(`**${name}**: ❌ unreachable`);
  }
}));

// UPS
try {
  const net = require('net');
  const UPS_HOST = process.env.UPS_HOST;
  const UPS_PORT = parseInt(process.env.UPS_PORT || '3551');
  if (UPS_HOST) {
    const upsRaw = await new Promise((resolve, reject) => {
      const client = net.createConnection(UPS_PORT, UPS_HOST, () => {
        const cmd = Buffer.alloc(8);
        cmd.writeUInt16BE(6, 0);
        cmd.write('status', 2);
        client.write(cmd);
      });
      let data = Buffer.alloc(0);
      client.on('data', c => { data = Buffer.concat([data, c]); });
      client.on('end', () => resolve(data.toString('ascii')));
      client.on('error', reject);
      setTimeout(() => { client.destroy(); reject(new Error('timeout')); }, 5000);
    });
    const kv = {};
    upsRaw.split('\n').forEach(line => {
      const i = line.indexOf(':');
      if (i > 0) kv[line.slice(0, i).trim()] = line.slice(i + 1).trim();
    });
    const model    = kv['MODEL']    || 'UPS';
    const status   = kv['STATUS']   || 'UNKNOWN';
    const bcharge  = kv['BCHARGE']  || '?';
    const loadpct  = kv['LOADPCT']  || '?';
    const timeleft = kv['TIMELEFT'] || '?';
    lines.push('');
    lines.push(`🔋 **UPS** (${model}): ${status} | Battery ${bcharge} | Load ${loadpct} | Runtime ${timeleft}`);
  }
} catch (err) {
  lines.push(`🔋 **UPS**: check failed — ${err.message}`);
}

// Prometheus scraper health
try {
  const promUrl = process.env.PROMETHEUS_URL;
  if (promUrl) {
    const resp = await $helpers.httpRequest({ method: 'GET', url: `${promUrl}/api/v1/query?query=up`, timeout: 8000 });
    const data  = typeof resp === 'string' ? JSON.parse(resp) : resp;
    const results = data?.data?.result || [];
    const up   = results.filter(r => r.value?.[1] === '1').length;
    const down = results.filter(r => r.value?.[1] === '0').length;
    lines.push('');
    lines.push(`📡 **Prometheus scrapers**: ${up} up, ${down} down`);
    if (down > 0) {
      results.filter(r => r.value?.[1] === '0').forEach(r => {
        lines.push(`   ❌ ${r.metric?.instance || r.metric?.job}`);
      });
    }
  }
} catch (err) {
  lines.push(`📡 **Prometheus**: check failed`);
}

lines.push('');
lines.push(`_Generated by NOLA — ${new Date().toUTCString()}_`);

return [{ json: { rawDigest: lines.join('\n') } }];

// Ask Ollama (knox — 10.0.18.25) to write a brief narrative for the weekly digest.
// Falls back gracefully if Ollama is unavailable.
const rawDigest = $input.first().json.rawDigest;

const ollamaUrl = process.env.OLLAMA_URL_KNOX || 'http://10.0.18.25:11434';
const model = process.env.OLLAMA_MODEL || 'llama3.2:3b';

const prompt = `You are NOLA, a homelab AI butler. Based on this weekly health report, write a single short paragraph (2-3 sentences) with your overall assessment of the lab's health this week. Be conversational but technical. Don't repeat all the numbers — give your read on whether things look good, concerning, or need attention.\n\nReport:\n${rawDigest}`;

let narrative = null;
try {
  const resp = await $helpers.httpRequest({
    method: 'POST',
    url: `${ollamaUrl}/api/generate`,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ model, prompt, stream: false }),
    timeout: 45000
  });
  const data = typeof resp === 'string' ? JSON.parse(resp) : resp;
  narrative = data?.response?.trim() || null;
} catch (err) {
  // Ollama unavailable — post digest without narrative
}

const message = narrative
  ? `${rawDigest}\n\n💬 **NOLA's Take:** ${narrative}`
  : rawDigest;

return [{ json: { message } }];
